const wh = $input.first().json;
const body = wh.body || wh.query || {};
const postId = String(body.post_id || '').trim();
if (!postId || !/^\d+$/.test(postId)) {
  throw new Error('Force Re-optimize: body.post_id (numeric) is required');
}
const keyword = String(body.keyword || '').trim();
return [{ json: { post_id: postId, keyword_override: keyword } }];

const sheetResp = $input.first().json;
const values = sheetResp.values || [];
if (values.length === 0) return [];
const headers = values[0].map(h => String(h || '').trim());
const colIdx = (name) => headers.indexOf(name);
const KW = colIdx('keyword');
const ESTADO = colIdx('estado');
const NICHO = colIdx('nicho');
const AUDIENCIA = colIdx('audiencia');
const INTENCION = colIdx('intencion');
const URL = colIdx('url_post');

const rows = [];
for (let i = 1; i < values.length; i++) {
  const r = values[i];
  if (!r || !r[ESTADO]) continue;
  if (String(r[ESTADO]).trim() !== 'Publicado') continue;
  if (!r[URL]) continue;
  rows.push({
    json: {
      keyword: String(r[KW] || '').trim(),
      estado: String(r[ESTADO] || '').trim(),
      nicho: String(r[NICHO] || '').trim(),
      audiencia: String(r[AUDIENCIA] || '').trim(),
      intencion: String(r[INTENCION] || '').trim(),
      url_post: String(r[URL] || '').trim(),
      row_number: i + 1
    }
  });
}
return rows;

const allPublished = $input.all();
const wpPost = $('WP GET Post').first().json;
const postId = String($('Validate Input').first().json.post_id || '');
const kwOverride = String($('Validate Input').first().json.keyword_override || '').trim();

const wpUrl = String(wpPost.link || '').trim().replace(/\/+$/, '');
const wpSlug = String(wpPost.slug || '').trim();

const target = allPublished.find(p => {
  const u = String(p.json.url_post || '').trim().replace(/\/+$/, '');
  if (u && u === wpUrl) return true;
  if (wpSlug && u.endsWith('/' + wpSlug)) return true;
  return false;
});

if (!target) {
  throw new Error('Force Re-optimize: WP post ' + postId + ' (' + wpUrl + ') no encontrado en Master Sheet con estado=Publicado. Verifica que la fila exista y que url_post coincida.');
}

const candidate = {
  ...target.json,
  keyword: kwOverride || target.json.keyword,
  id: postId,
  content: { raw: String(wpPost.content?.raw || wpPost.content?.rendered || '') },
  gsc_position: 0,
  gsc_impressions: 0
};

return [{ json: candidate }];

const gptItems  = $input.all();
const metaItems = $('Construir Prompt GPT Refresh').all();

function strip4Byte(str) {
  if (typeof str !== 'string') return str;
  return str.replace(/[\u{10000}-\u{10FFFF}]/gu, '');
}

function scrubAIWatermarks(str) {
  if (typeof str !== 'string' || !str) return str;
  str = str.replace(/\p{Cf}/gu, '');
  str = str.replace(/\s+[—–]\s+([A-ZÁÉÍÓÚÑ][a-záéíóúñ]+)/g, ', $1');
  str = str.replace(/\s+[—–]\s+(?=[A-ZÁÉÍÓÚÑ])/g, '. ');
  str = str.replace(/\s*[—–]\s*/g, ', ');
  str = str.replace(/[ \t]+/g, ' ');
  str = str.replace(/ ([,.!?;:])/g, '$1');
  str = str.replace(/\n{3,}/g, '\n\n');
  return str;
}

function stripH1(html) {
  if (!html) return '';
  return html.replace(/^\s*<h1[^>]*>[\s\S]*?<\/h1>\s*/i, '').trim();
}

function capitalizarPrimera(str) {
  if (!str) return '';
  return str.replace(/[a-záéíóúüñA-ZÁÉÍÓÚÜÑ]/, c => c.toUpperCase());
}

function aplicarInterrogacion(str) {
  if (!str) return '';
  const trimmed = str.trim();
  const startsQ = /^(qué|que|cuánto|cuanto|cómo|como|cuál|cual|por qué|por que|cuándo|cuando|dónde|donde|quién|quien|es |son |puede|pueden|debo|debería|sirve|funciona|existe|hay)/i.test(trimmed);
  if (startsQ && !trimmed.startsWith('¿')) return '¿' + trimmed + (trimmed.endsWith('?') ? '' : '?');
  return trimmed;
}

function capitalizarHeadings(html) {
  return html.replace(/(<h[2-4][^>]*>)([\s\S]*?)(<\/h[2-4]>)/gi, (m, open, content, close) => {
    let fixed = content.replace(/[a-záéíóúüñ]/i, c => c.toUpperCase());
    fixed = fixed.replace(/:\s+([a-záéíóúüñ])/gi, (_, l) => ': ' + l.toUpperCase());
    fixed = aplicarInterrogacion(fixed);
    return open + fixed + close;
  });
}

function limpiarFAQ(html) {
  return html
    .replace(/<blockquote[^>]*>/gi, '')
    .replace(/<\/blockquote>/gi, '')
    .replace(/^(&gt;|>)+\s*/gm, '')
    .replace(/<p>\s*(&gt;|>)+\s*/g, '<p>');
}

function truncarMeta(str, max) {
  if (!str || str.length <= max) return str;
  const cut = str.substring(0, max);
  const lastSpace = cut.lastIndexOf(' ');
  return lastSpace > max - 20 ? cut.substring(0, lastSpace) : cut;
}

function buildFAQHtml(items) {
  if (!items || items.length === 0) return '';
  const rows = items.map(item => {
    const q = scrubAIWatermarks(aplicarInterrogacion(capitalizarPrimera((item.question || '').trim())));
    const a = scrubAIWatermarks((item.answer || '').trim());
    return '<h3>' + q + '</h3>\n<p>' + a + '</p>';
  }).join('\n');
  return '<h2>Preguntas frecuentes</h2>\n' + rows;
}

function buildFAQJsonLD(items) {
  if (!items || items.length === 0) return '';
  const entities = items.map(item => ({
    '@type': 'Question',
    'name': scrubAIWatermarks(aplicarInterrogacion(capitalizarPrimera((item.question || '').trim()))),
    'acceptedAnswer': { '@type': 'Answer', 'text': scrubAIWatermarks((item.answer || '').trim()) }
  }));
  const schema = { '@context': 'https://schema.org', '@type': 'FAQPage', 'mainEntity': entities };
  return '<script type="application/ld+json">\n' + JSON.stringify(schema) + '\n</script>';
}

function buildFuentesHtml(items) {
  if (!items || items.length === 0) return '';
  const valid = items.filter(it => it && it.url && it.nombre);
  if (valid.length === 0) return '';
  const stripInvisibles = (s) => {
    if (typeof s !== 'string') return '';
    return s.replace(/[​-‍﻿⁠­ ]/g, '').replace(/\p{Cf}/gu, '').trim();
  };
  const rows = valid.map(it => {
    const nombre = stripInvisibles(String(it.nombre || ''));
    const url = stripInvisibles(String(it.url || ''));
    const desc = stripInvisibles(String(it.descripcion || ''));
    const descPart = desc ? ' — ' + desc : '';
    return '<li><a href="' + url + '" rel="nofollow noopener" target="_blank">' + nombre + '</a>' + descPart + '</li>';
  }).join('\n');
  return '<section class="fuentes-consultadas">\n<h2>Fuentes consultadas</h2>\n<p>El contenido de este artículo se apoya en publicaciones de organizaciones veterinarias autoritativas. Te invitamos a consultarlas para profundizar:</p>\n<ul>\n' + rows + '\n</ul>\n</section>';
}

function buildSpeakableJsonLD(entities) {
  const schema = {
    '@context': 'https://schema.org',
    '@type': 'WebPage',
    'speakable': {
      '@type': 'SpeakableSpecification',
      'cssSelector': ['.respuesta-directa', '.key-takeaways']
    }
  };
  const valid = (entities || []).filter(e => e && e.nombre && e.wikipedia_url && /^https:\/\/[a-z]{2,3}\.wikipedia\.org\//.test(e.wikipedia_url));
  if (valid.length > 0) {
    schema.mentions = valid.map(e => ({
      '@type': 'Thing',
      'name': scrubAIWatermarks(String(e.nombre).trim()),
      'sameAs': String(e.wikipedia_url).trim()
    }));
  }
  return '<script type="application/ld+json">\n' + JSON.stringify(schema) + '\n</script>';
}

function buildHowToJsonLD(steps, name) {
  if (!steps || !Array.isArray(steps) || steps.length < 4) return '';
  const valid = steps.filter(s => s && s.name && s.text);
  if (valid.length < 4) return '';
  const stepsList = valid.map((s, i) => ({
    '@type': 'HowToStep',
    'position': i + 1,
    'name': scrubAIWatermarks(String(s.name).trim()),
    'text': scrubAIWatermarks(String(s.text).trim())
  }));
  const schema = {
    '@context': 'https://schema.org',
    '@type': 'HowTo',
    'name': scrubAIWatermarks(String(name || '').trim()),
    'step': stepsList
  };
  return '<script type="application/ld+json">\n' + JSON.stringify(schema) + '\n</script>';
}

const now = new Date();
const colombiaOffset = -5 * 60;
const colombiaTime = new Date(now.getTime() + (colombiaOffset - now.getTimezoneOffset()) * 60000);
const today = colombiaTime.toISOString().split('T')[0];
const results = [];

for (let i = 0; i < gptItems.length; i++) {
  const raw  = gptItems[i].json.choices?.[0]?.message?.content || '';
  const meta = metaItems[i] ? metaItems[i].json : {};

  let result;
  try {
    result = JSON.parse(raw);
  } catch(e) {
    throw new Error('Fase D GPT parse error [item ' + i + ']: ' + raw.substring(0, 200));
  }

  let bodyHtml = strip4Byte(result.body_html || '');
  bodyHtml = stripH1(bodyHtml);
  bodyHtml = limpiarFAQ(bodyHtml);
  bodyHtml = capitalizarHeadings(bodyHtml);

  // Inyecta respuesta_directa como PRIMER párrafo (AI Search)
  const respuestaDirecta = (result.respuesta_directa || '').trim();
  if (respuestaDirecta) {
    bodyHtml = '<p class="respuesta-directa">' + respuestaDirecta + '</p>\n\n' + bodyHtml;
  }

  // Inyecta key_takeaways como blockquote antes del primer H2 (Featured Snippet)
  const takeaways = (result.key_takeaways || []).filter(t => t && String(t).trim());
  if (takeaways.length >= 3) {
    const items2 = takeaways.map(t => '<li>' + String(t).trim() + '</li>').join('\n');
    const takeawaysHtml = '<blockquote class="key-takeaways">\n<p><strong>Conclusiones rápidas</strong></p>\n<ul>\n' + items2 + '\n</ul>\n</blockquote>';
    const firstH2 = bodyHtml.search(/<h2[^>]*>/i);
    if (firstH2 > 0) {
      bodyHtml = bodyHtml.slice(0, firstH2) + takeawaysHtml + '\n\n' + bodyHtml.slice(firstH2);
    } else {
      bodyHtml = takeawaysHtml + '\n\n' + bodyHtml;
    }
  }

  const faqItems  = result.faq_items || [];
  const faqHtml   = buildFAQHtml(faqItems);
  const faqJsonLD = buildFAQJsonLD(faqItems);
  if (faqHtml)   bodyHtml += '\n' + faqHtml;

  // SCRUB sobre body+takeaways+FAQ (antes de añadir fuentes que usan em-dashes literales)
  bodyHtml = scrubAIWatermarks(bodyHtml);

  // Append bloque de Fuentes consultadas (valores pre-scrubbed dentro de buildFuentesHtml)
  const fuentesHtml = buildFuentesHtml(result.fuentes_consultadas || []);
  if (fuentesHtml) bodyHtml += '\n' + fuentesHtml;

  if (faqJsonLD) bodyHtml += '\n' + faqJsonLD;

  // AEO: WebPage schema con Speakable (asistentes de voz) + mentions (Knowledge Graph vía Wikipedia sameAs)
  bodyHtml += '\n' + buildSpeakableJsonLD(result.entities || []);

  // HowTo schema (solo si GPT identificó la keyword como procedural)
  const howToHtml = buildHowToJsonLD(result.howto_steps || [], result.seo_title || '');
  if (howToHtml) bodyHtml += '\n' + howToHtml;

  const seoTitle = scrubAIWatermarks(strip4Byte(truncarMeta(capitalizarPrimera(result.seo_title || ''), 60)));
  const metaDesc = scrubAIWatermarks(strip4Byte(truncarMeta(result.meta_description || '', 145)));

  const tags = result.tags || [];
  const tagsList = tags.map(t => String(t).toLowerCase().trim().replace(/^#+/, '')).filter(Boolean);

  const wpPatchPayload = JSON.stringify({
    content: bodyHtml,
    meta: {
      _yoast_wpseo_title:    seoTitle,
      _yoast_wpseo_metadesc: metaDesc,
      _yoast_wpseo_focuskw:  meta.keyword || ''
    }
  });

  const sheetUpdatePayload = JSON.stringify({
    valueInputOption: 'USER_ENTERED',
    data: [
      { range: `Blog!J${meta.row_number}`, values: [[String(meta.gsc_position || '')]] },
      { range: `Blog!M${meta.row_number}`, values: [[today]] }
    ]
  });

  results.push({
    json: {
      wp_patch_json:      wpPatchPayload,
      sheet_update_json:  sheetUpdatePayload,
      wp_post_id:         String(meta.wp_post_id || ''),
      keyword:            meta.keyword    || '',
      url_post:           meta.url_post   || '',
      row_number:         meta.row_number,
      seo_title:          seoTitle,
      meta_description:   metaDesc,
      tags_list:          JSON.stringify(tagsList),
      gsc_position:       meta.gsc_position    || 0,
      fecha_reoptimizado: today
    }
  });
}

return results;

const data = $input.item.json;
const wpPatch = JSON.parse(data.wp_patch_json);
const keyword = data.keyword || '';
const currentUrl = (data.url_post || '').trim().replace(/\/+$/, '');

const publishedItems = $('Leer Posts Publicados').all();
const realPosts = publishedItems
  .filter(it => it.json.url_post && it.json.keyword)
  .map(it => ({
    keyword: String(it.json.keyword).toLowerCase().trim(),
    url: String(it.json.url_post).trim().replace(/\/+$/, '')
  }))
  .filter(p => p.url !== currentUrl);

const realUrlSet = new Set(realPosts.map(p => p.url));
let body = wpPatch.content;

function reEscape(s) { return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

// Strip URLs alucinadas
let strippedCount = 0;
body = body.replace(
  /<a\s+href="(https?:\/\/bigotescaninos\.com\/[^"]+)"[^>]*>([^<]+)<\/a>/gi,
  (match, url, anchor) => {
    const clean = url.replace(/\/+$/, '').split('#')[0];
    if (realUrlSet.has(clean)) return match;
    strippedCount++;
    return anchor;
  }
);

function collectLinkRanges(text) {
  const ranges = [];
  const re = /<a\b[^>]*>[^<]*<\/a>/gi;
  let m;
  while ((m = re.exec(text)) !== null) ranges.push([m.index, m.index + m[0].length]);
  return ranges;
}
let allLinkRanges = collectLinkRanges(body);
const currentInternalCount = (body.match(/href="https?:\/\/bigotescaninos\.com[^"]+"/g) || []).length;

const targetMin = 2;
const usedUrls = new Set(
  (body.match(/href="(https?:\/\/bigotescaninos\.com[^"]+)"/g) || [])
    .map(s => s.match(/href="([^"]+)"/)[1].replace(/\/+$/, ''))
);
let injected = 0;
const needed = Math.max(0, targetMin - currentInternalCount);

if (needed > 0) {
  for (const post of realPosts) {
    if (injected >= needed) break;
    if (usedUrls.has(post.url)) continue;

    const kwRe = new RegExp('\\b' + reEscape(post.keyword) + '\\b', 'gi');
    let mm;
    let foundIdx = -1;
    let foundLen = 0;
    while ((mm = kwRe.exec(body)) !== null) {
      const inAnyLink = allLinkRanges.some(([s, e]) => mm.index >= s && mm.index < e);
      if (!inAnyLink) { foundIdx = mm.index; foundLen = mm[0].length; break; }
    }
    if (foundIdx === -1) continue;

    const matched = body.substring(foundIdx, foundIdx + foundLen);
    const replacement = '<a href="' + post.url + '">' + matched + '</a>';
    body = body.substring(0, foundIdx) + replacement + body.substring(foundIdx + foundLen);
    allLinkRanges = collectLinkRanges(body);
    usedUrls.add(post.url);
    injected++;
  }
}

wpPatch.content = body;
const newWpPatchJson = JSON.stringify(wpPatch);

return {
  json: {
    ...data,
    wp_patch_json: newWpPatchJson,
    linker_stripped: strippedCount,
    linker_injected: injected,
    linker_total_internal: currentInternalCount + injected
  }
};

const data = $input.item.json;
const wpPatch = JSON.parse(data.wp_patch_json);
const keyword = data.keyword || '';

const bodyText = wpPatch.content
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const wordCount = bodyText.split(/\s+/).filter(w => w.length > 0).length;

const checks = {};
const breakdown = [];

function reEscape(s) { return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

checks.wordCount = wordCount >= 1800 ? 10 : Math.max(0, Math.round((wordCount / 1800) * 10));
breakdown.push(`Palabras: ${wordCount}/1800 → ${checks.wordCount}/10`);

const h2Count = (wpPatch.content.match(/<h2[^>]*>/gi) || []).length;
checks.h2Count = (h2Count >= 4 && h2Count <= 8) ? 10 : (h2Count >= 3 ? 6 : 2);
breakdown.push(`H2: ${h2Count} (target 4-7) → ${checks.h2Count}/10`);

const kwLower = keyword.toLowerCase();
const first200 = bodyText.substring(0, 200).toLowerCase();
checks.keywordIntro = first200.includes(kwLower) ? 10 : 0;
breakdown.push(`Keyword en primeros 200 chars: ${checks.keywordIntro === 10 ? 'YES' : 'NO'} → ${checks.keywordIntro}/10`);

const kwOcc = (bodyText.toLowerCase().match(new RegExp(reEscape(kwLower), 'g')) || []).length;
const density = wordCount > 0 ? kwOcc / wordCount : 0;
checks.density = (density >= 0.005 && density <= 0.02) ? 10 : (density > 0 && density <= 0.03) ? 5 : 0;
breakdown.push(`Density: ${(density*100).toFixed(2)}% (${kwOcc}/${wordCount}) → ${checks.density}/10`);

const internalLinks = (wpPatch.content.match(/href="https?:\/\/bigotescaninos\.com\/[^"#]+"/g) || []).length;
checks.internalLinks = internalLinks >= 2 ? 5 : (internalLinks * 2);
breakdown.push(`Internal links: ${internalLinks}/2 → ${checks.internalLinks}/5`);

const externalLinks = (wpPatch.content.match(/href="https?:\/\/(?!bigotescaninos\.com)[^"]+"[^>]*rel="[^"]*nofollow/gi) || []).length;
checks.externalLinks = externalLinks >= 1 ? 5 : 0;
breakdown.push(`External nofollow: ${externalLinks}/1 → ${checks.externalLinks}/5`);

const metaTitleLen = (wpPatch.meta._yoast_wpseo_title || '').length;
checks.metaTitle = (metaTitleLen >= 50 && metaTitleLen <= 60) ? 5 : 0;
breakdown.push(`SEO title: ${metaTitleLen} chars (50-60) → ${checks.metaTitle}/5`);

const metaDescLen = (wpPatch.meta._yoast_wpseo_metadesc || '').length;
checks.metaDesc = (metaDescLen >= 130 && metaDescLen <= 145) ? 5 : 0;
breakdown.push(`Meta desc: ${metaDescLen} chars (130-145) → ${checks.metaDesc}/5`);

const firstPMatch = wpPatch.content.match(/^<p>([^<]+)<\/p>/);
const firstParaLen = firstPMatch ? firstPMatch[1].length : 0;
checks.directAnswer = (firstParaLen >= 80 && firstParaLen <= 320) ? 5 : 0;
breakdown.push(`Respuesta directa: ${firstParaLen} chars (80-320) → ${checks.directAnswer}/5`);

checks.keyTakeaways = wpPatch.content.includes('class="key-takeaways"') ? 5 : 0;
breakdown.push(`Key takeaways block: ${checks.keyTakeaways === 5 ? 'YES' : 'NO'} → ${checks.keyTakeaways}/5`);

checks.faq = (wpPatch.content.includes('Preguntas frecuentes') && wpPatch.content.includes('FAQPage')) ? 5 : 0;
breakdown.push(`FAQ + JSON-LD: ${checks.faq === 5 ? 'YES' : 'NO'} → ${checks.faq}/5`);

const prohibited = ['en el mundo de','cuando se trata de','es importante señalar','cabe destacar','en la era digital','hoy en día','en el dinámico mundo','en última instancia','mascota'];
const lowerBody = bodyText.toLowerCase();
const violations = prohibited.filter(p => lowerBody.includes(p));
checks.prohibited = violations.length === 0 ? 10 : Math.max(0, 10 - violations.length * 3);
breakdown.push(`Frases prohibidas: ${violations.length === 0 ? 'CLEAN' : violations.join(' | ')} → ${checks.prohibited}/10`);

const miniRegex = /\b[A-ZÁÉÍÓÚÑ][a-záéíóúñ]{2,}, (?:un|una|el|la|de) [a-záéíóúñ]+/g;
const miniMatches = (bodyText.match(miniRegex) || []).length;
checks.miniStories = miniMatches >= 2 ? 5 : (miniMatches === 1 ? 3 : 0);
breakdown.push(`Mini-historias detectadas: ~${miniMatches}/2 → ${checks.miniStories}/5`);

const sentences = bodyText.split(/[.!?]+/).filter(s => s.trim().length > 5);
const avgSent = sentences.length > 0 ? sentences.reduce((s, x) => s + x.split(/\s+/).length, 0) / sentences.length : 0;
checks.sentenceLen = avgSent <= 25 ? 5 : (avgSent <= 30 ? 3 : 0);
breakdown.push(`Avg sentence: ${avgSent.toFixed(1)} palabras (<25) → ${checks.sentenceLen}/5`);

let tagsCount = 0;
try {
  const t = JSON.parse(data.tags_list || '[]');
  tagsCount = Array.isArray(t) ? t.length : 0;
} catch(e) {}
checks.tags = tagsCount >= 5 ? 5 : tagsCount;
breakdown.push(`Tags: ${tagsCount}/5 → ${checks.tags}/5`);

// Fuentes consultadas: section + >= 3 sources (5 pts)
const fuentesSection = wpPatch.content.match(/<section class="fuentes-consultadas">[\s\S]*?<\/section>/);
const fuentesCount = fuentesSection ? (fuentesSection[0].match(/<li>/g) || []).length : 0;
checks.fuentesConsultadas = fuentesCount >= 3 ? 5 : (fuentesCount > 0 ? Math.round((fuentesCount / 3) * 5) : 0);
breakdown.push(`Fuentes consultadas: ${fuentesCount}/3 → ${checks.fuentesConsultadas}/5`);

// Tabla o data-box obligatoria (10 pts + HARD GATE)
const hasTable = /<table[^>]*>/i.test(wpPatch.content) || /<dl[^>]*>/i.test(wpPatch.content);
checks.tableData = hasTable ? 10 : 0;
breakdown.push(`Tabla/data-box: ${hasTable ? 'YES' : 'NO'} → ${checks.tableData}/10`);

// H2 question-first ratio (5 pts) — solo H2 del cuerpo
const allH2 = wpPatch.content.match(/<h2[^>]*>([\s\S]*?)<\/h2>/gi) || [];
const structuralH2 = /Conclusi[óo]n|Preguntas frecuentes|Fuentes consultadas/i;
const bodyH2 = allH2.filter(h => !structuralH2.test(h));
const h2Questions = bodyH2.filter(h => /<h2[^>]*>\s*¿/i.test(h)).length;
const h2Ratio = bodyH2.length > 0 ? h2Questions / bodyH2.length : 0;
checks.h2QuestionFirst = h2Ratio >= 0.6 ? 5 : (h2Ratio >= 0.4 ? 3 : (h2Ratio >= 0.2 ? 1 : 0));
breakdown.push(`H2 question-first (cuerpo): ${h2Questions}/${bodyH2.length} (${(h2Ratio*100).toFixed(0)}%) → ${checks.h2QuestionFirst}/5`);

const totalScore = Object.values(checks).reduce((s, v) => s + v, 0);
const breakdownStr = breakdown.join('\n');

if (!hasTable) {
  throw new Error(`Quality gate WF3 FAIL — artículo sin <table> ni <dl> obligatoria [keyword: ${keyword}]:\n${breakdownStr}`);
}

if (totalScore < 70) {
  throw new Error(`Quality gate WF3 failed (${totalScore}/120) [keyword: ${keyword}]:\n${breakdownStr}`);
}

return {
  json: {
    ...data,
    quality_score: totalScore,
    quality_breakdown: breakdownStr
  }
};

const parseItems = $('Parsear Respuesta GPT').all();
const result = [];
for (const item of parseItems) {
  const wpPostId = item.json.wp_post_id;
  let tags = [];
  try { tags = JSON.parse(item.json.tags_list || '[]'); } catch(e) {}
  for (const tag of tags) {
    const t = String(tag).trim();
    if (t) result.push({ json: { tag_name: t, wp_post_id: wpPostId } });
  }
}
return result;

const tagResponses = $input.all();
const tagInputs = $('Tags Split WF3').all();

const postTagMap = {};
for (let i = 0; i < tagResponses.length; i++) {
